#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t P,Q; scanf("%" PRId64 " %" PRId64, &P, &Q);
        int64_t sum = P + Q;
        int64_t block = sum / 222;
        if(block % 2 == 0) printf("Alice\n");
        else printf("Bob\n");
    }
    return 0;
}

